#!/usr/bin/env node

import fs from "node:fs/promises";
import path from "node:path";
import process from "node:process";

const DEFAULT_WIDTH = 1200;
const DEFAULT_HEIGHT = 760;
const API_COLORS = {
  webgl2: "#1f77b4",
  webgpu: "#d62728",
};

function usage() {
  console.log(
    [
      "Usage:",
      "  node tools/plot-failure-curve.mjs --in <failure_curve.json> [options]",
      "",
      "Options:",
      "  --in <path>         Input JSON generated by tools/failure-curve.mjs (required)",
      "  --out <path>        Output SVG path (default: <in base>.svg)",
      "  --mode <mode>       canvas | xr | all (default: xr)",
      "  --apis <list>       Comma list: webgl2,webgpu (default: webgl2,webgpu)",
      "  --ci <0|1>          Draw Wilson 95% CI bars (default: 1)",
      "  --title <text>      Chart title",
      "  --subtitle <text>   Optional subtitle line",
      "  --width <px>        SVG width (default: 1200)",
      "  --height <px>       SVG height (default: 760)",
      "  -h, --help          Show this help",
      "",
      "Output:",
      "  Writes a single SVG line chart with failure-rate curves by API.",
    ].join("\n")
  );
}

function parseBooleanFlag(value, key) {
  if (value === "1") return true;
  if (value === "0") return false;
  throw new Error(`Invalid ${key} value: ${value}. Expected 0 or 1.`);
}

function asFiniteNumber(value) {
  return typeof value === "number" && Number.isFinite(value) ? value : null;
}

function isObject(value) {
  return value !== null && typeof value === "object" && !Array.isArray(value);
}

function escapeXml(value) {
  return String(value)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");
}

function parseArgs(argv) {
  const opts = {
    inputPath: null,
    outputPath: null,
    mode: "xr",
    apis: ["webgl2", "webgpu"],
    drawCi: true,
    title: null,
    subtitle: null,
    width: DEFAULT_WIDTH,
    height: DEFAULT_HEIGHT,
  };

  for (let i = 0; i < argv.length; i++) {
    const arg = argv[i];
    if (arg === "-h" || arg === "--help") return { help: true, opts };
    if (arg === "--in") {
      opts.inputPath = argv[++i] || null;
      continue;
    }
    if (arg.startsWith("--in=")) {
      opts.inputPath = arg.slice("--in=".length) || null;
      continue;
    }
    if (arg === "--out") {
      opts.outputPath = argv[++i] || null;
      continue;
    }
    if (arg.startsWith("--out=")) {
      opts.outputPath = arg.slice("--out=".length) || null;
      continue;
    }
    if (arg === "--mode") {
      opts.mode = argv[++i] || "";
      continue;
    }
    if (arg.startsWith("--mode=")) {
      opts.mode = arg.slice("--mode=".length);
      continue;
    }
    if (arg === "--apis") {
      opts.apis = String(argv[++i] || "")
        .split(",")
        .map((v) => v.trim())
        .filter(Boolean);
      continue;
    }
    if (arg.startsWith("--apis=")) {
      opts.apis = arg
        .slice("--apis=".length)
        .split(",")
        .map((v) => v.trim())
        .filter(Boolean);
      continue;
    }
    if (arg === "--ci") {
      opts.drawCi = parseBooleanFlag(argv[++i] || "", "--ci");
      continue;
    }
    if (arg.startsWith("--ci=")) {
      opts.drawCi = parseBooleanFlag(arg.slice("--ci=".length), "--ci");
      continue;
    }
    if (arg === "--title") {
      opts.title = argv[++i] || null;
      continue;
    }
    if (arg.startsWith("--title=")) {
      opts.title = arg.slice("--title=".length) || null;
      continue;
    }
    if (arg === "--subtitle") {
      opts.subtitle = argv[++i] || null;
      continue;
    }
    if (arg.startsWith("--subtitle=")) {
      opts.subtitle = arg.slice("--subtitle=".length) || null;
      continue;
    }
    if (arg === "--width") {
      opts.width = Number(argv[++i]);
      continue;
    }
    if (arg.startsWith("--width=")) {
      opts.width = Number(arg.slice("--width=".length));
      continue;
    }
    if (arg === "--height") {
      opts.height = Number(argv[++i]);
      continue;
    }
    if (arg.startsWith("--height=")) {
      opts.height = Number(arg.slice("--height=".length));
      continue;
    }
    throw new Error(`Unknown option: ${arg}`);
  }

  if (!opts.inputPath) throw new Error("Missing required --in <path>.");
  if (!["canvas", "xr", "all"].includes(opts.mode)) {
    throw new Error(`Invalid --mode value: ${opts.mode}. Expected canvas, xr, or all.`);
  }
  if (!Number.isFinite(opts.width) || opts.width < 400) {
    throw new Error(`Invalid --width value: ${opts.width}. Expected numeric >= 400.`);
  }
  if (!Number.isFinite(opts.height) || opts.height < 300) {
    throw new Error(`Invalid --height value: ${opts.height}. Expected numeric >= 300.`);
  }
  if (!opts.apis.length) {
    throw new Error("No APIs selected. Use --apis webgl2,webgpu.");
  }
  for (const api of opts.apis) {
    if (api !== "webgl2" && api !== "webgpu") {
      throw new Error(`Invalid api in --apis: ${api}. Expected webgl2 or webgpu.`);
    }
  }
  return { help: false, opts };
}

function mapX(inst, minInst, maxInst, left, plotWidth) {
  if (minInst === maxInst) return left + plotWidth / 2;
  return left + ((inst - minInst) / (maxInst - minInst)) * plotWidth;
}

function mapY(rate, top, plotHeight) {
  return top + (1 - rate) * plotHeight;
}

function generateSvg({
  rows,
  title,
  subtitle,
  width,
  height,
  drawCi,
}) {
  const margin = { top: 90, right: 40, bottom: 90, left: 90 };
  const plotWidth = width - margin.left - margin.right;
  const plotHeight = height - margin.top - margin.bottom;

  const instances = Array.from(
    new Set(rows.map((r) => r.instances).filter((v) => Number.isFinite(v)))
  ).sort((a, b) => a - b);
  if (!instances.length) throw new Error("No numeric instances available after filtering.");

  const minInst = instances[0];
  const maxInst = instances[instances.length - 1];

  const yTicks = [0, 0.25, 0.5, 0.75, 1];
  const apiOrder = Array.from(new Set(rows.map((r) => r.api))).sort((a, b) => a.localeCompare(b));

  const byApi = new Map();
  for (const api of apiOrder) byApi.set(api, []);
  for (const row of rows) {
    if (!byApi.has(row.api)) byApi.set(row.api, []);
    byApi.get(row.api).push(row);
  }
  for (const api of byApi.keys()) {
    byApi.get(api).sort((a, b) => a.instances - b.instances);
  }

  const parts = [];
  parts.push(`<?xml version="1.0" encoding="UTF-8"?>`);
  parts.push(`<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}" role="img" aria-label="${escapeXml(title)}">`);
  parts.push(`<rect x="0" y="0" width="${width}" height="${height}" fill="#ffffff" />`);

  parts.push(`<text x="${margin.left}" y="40" font-family="Helvetica, Arial, sans-serif" font-size="28" font-weight="700" fill="#111111">${escapeXml(title)}</text>`);
  if (subtitle) {
    parts.push(`<text x="${margin.left}" y="66" font-family="Helvetica, Arial, sans-serif" font-size="15" fill="#444444">${escapeXml(subtitle)}</text>`);
  }

  parts.push(`<rect x="${margin.left}" y="${margin.top}" width="${plotWidth}" height="${plotHeight}" fill="#fafafa" stroke="#d9d9d9" stroke-width="1" />`);

  for (const tick of yTicks) {
    const y = mapY(tick, margin.top, plotHeight);
    const dash = tick === 0 || tick === 1 ? "" : ` stroke-dasharray="4 4"`;
    parts.push(`<line x1="${margin.left}" y1="${y}" x2="${margin.left + plotWidth}" y2="${y}" stroke="#e1e1e1" stroke-width="1"${dash} />`);
    parts.push(`<text x="${margin.left - 12}" y="${y + 5}" text-anchor="end" font-family="Helvetica, Arial, sans-serif" font-size="12" fill="#333333">${Math.round(tick * 100)}%</text>`);
  }

  for (const inst of instances) {
    const x = mapX(inst, minInst, maxInst, margin.left, plotWidth);
    parts.push(`<line x1="${x}" y1="${margin.top}" x2="${x}" y2="${margin.top + plotHeight}" stroke="#f0f0f0" stroke-width="1" />`);
    parts.push(`<text x="${x}" y="${margin.top + plotHeight + 24}" text-anchor="middle" font-family="Helvetica, Arial, sans-serif" font-size="12" fill="#333333">${inst}</text>`);
  }

  parts.push(`<text x="${margin.left + plotWidth / 2}" y="${height - 24}" text-anchor="middle" font-family="Helvetica, Arial, sans-serif" font-size="14" fill="#111111">Instances</text>`);
  parts.push(`<text transform="translate(24 ${margin.top + plotHeight / 2}) rotate(-90)" text-anchor="middle" font-family="Helvetica, Arial, sans-serif" font-size="14" fill="#111111">Failure Rate</text>`);

  for (const api of apiOrder) {
    const series = byApi.get(api) || [];
    if (!series.length) continue;
    const color = API_COLORS[api] || "#555555";
    const path = [];
    for (const row of series) {
      const x = mapX(row.instances, minInst, maxInst, margin.left, plotWidth);
      const y = mapY(row.fail_rate, margin.top, plotHeight);
      path.push(`${path.length === 0 ? "M" : "L"} ${x.toFixed(2)} ${y.toFixed(2)}`);
    }
    parts.push(`<path d="${path.join(" ")}" fill="none" stroke="${color}" stroke-width="3" />`);

    for (const row of series) {
      const x = mapX(row.instances, minInst, maxInst, margin.left, plotWidth);
      const y = mapY(row.fail_rate, margin.top, plotHeight);
      if (drawCi) {
        const ciLower = asFiniteNumber(row.fail_rate_ci95?.lower);
        const ciUpper = asFiniteNumber(row.fail_rate_ci95?.upper);
        if (ciLower !== null && ciUpper !== null) {
          const y1 = mapY(ciLower, margin.top, plotHeight);
          const y2 = mapY(ciUpper, margin.top, plotHeight);
          parts.push(`<line x1="${x}" y1="${y1}" x2="${x}" y2="${y2}" stroke="${color}" stroke-width="1.5" opacity="0.75" />`);
          parts.push(`<line x1="${x - 5}" y1="${y1}" x2="${x + 5}" y2="${y1}" stroke="${color}" stroke-width="1.5" opacity="0.75" />`);
          parts.push(`<line x1="${x - 5}" y1="${y2}" x2="${x + 5}" y2="${y2}" stroke="${color}" stroke-width="1.5" opacity="0.75" />`);
        }
      }
      parts.push(`<circle cx="${x}" cy="${y}" r="4.5" fill="${color}" stroke="#ffffff" stroke-width="1.5" />`);
    }
  }

  const legendX = margin.left + plotWidth - 180;
  let legendY = margin.top + 18;
  parts.push(`<rect x="${legendX - 12}" y="${legendY - 16}" width="192" height="${apiOrder.length * 24 + 22}" fill="#ffffff" stroke="#d9d9d9" />`);
  for (const api of apiOrder) {
    const color = API_COLORS[api] || "#555555";
    parts.push(`<line x1="${legendX}" y1="${legendY}" x2="${legendX + 28}" y2="${legendY}" stroke="${color}" stroke-width="3" />`);
    parts.push(`<circle cx="${legendX + 14}" cy="${legendY}" r="4.2" fill="${color}" stroke="#ffffff" stroke-width="1.2" />`);
    parts.push(`<text x="${legendX + 36}" y="${legendY + 4}" font-family="Helvetica, Arial, sans-serif" font-size="13" fill="#222222">${escapeXml(api)}</text>`);
    legendY += 24;
  }

  parts.push(`</svg>`);
  return parts.join("\n");
}

async function main() {
  let parsed;
  try {
    parsed = parseArgs(process.argv.slice(2));
  } catch (err) {
    console.error(err.message || err);
    usage();
    process.exit(1);
  }

  if (parsed.help) {
    usage();
    process.exit(0);
  }

  const { opts } = parsed;
  let report;
  try {
    const content = await fs.readFile(opts.inputPath, "utf8");
    report = JSON.parse(content);
  } catch (err) {
    console.error(`Failed to read/parse input JSON: ${err.message || err}`);
    process.exit(1);
  }

  if (!report || !Array.isArray(report.curve_rows)) {
    console.error("Input JSON does not look like a failure-curve report (missing curve_rows array).");
    process.exit(1);
  }

  const rows = report.curve_rows.filter((row) => {
    if (!isObject(row)) return false;
    if (!opts.apis.includes(row.api)) return false;
    if (opts.mode !== "all" && row.mode !== opts.mode) return false;
    return Number.isFinite(row.instances) && Number.isFinite(row.fail_rate);
  });
  if (!rows.length) {
    console.error("No rows matched the requested filters.");
    process.exit(1);
  }

  const defaultTitleMode = opts.mode === "all" ? "All Modes" : opts.mode.toUpperCase();
  const title = opts.title || `Failure-Rate Curve (${defaultTitleMode})`;
  const totals = isObject(report.totals) ? report.totals : {};
  const subtitle = opts.subtitle || `records=${totals.records_total ?? "?"}, failed=${totals.records_failed ?? "?"}, ci=Wilson95`;

  const svg = generateSvg({
    rows,
    title,
    subtitle,
    width: opts.width,
    height: opts.height,
    drawCi: opts.drawCi,
  });

  const outPath = opts.outputPath
    ? path.resolve(process.cwd(), opts.outputPath)
    : path.resolve(
        process.cwd(),
        `${opts.inputPath.replace(/\.(json)$/i, "").replace(/\.(JSON)$/i, "")}.svg`
      );

  await fs.mkdir(path.dirname(outPath), { recursive: true });
  await fs.writeFile(outPath, svg, "utf8");
  console.log(`Wrote ${outPath}`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
